package csharp

import (
	"github.com/sofa-buffers/generator/internal/generator"
	"github.com/sofa-buffers/generator/internal/ir"
)

// projectFiles scaffolds a buildable .NET console project with a
// System.Text.Json encode/decode harness over corelib-cs.
func (g *gen) projectFiles(s *ir.Schema, cfg map[string]any) []generator.File {
	return []generator.File{
		{Path: "harness.csproj", Content: []byte(csproj)},
		{Path: "Program.cs", Content: g.harness(s)},
		{Path: "README.md", Content: []byte(csReadme)},
	}
}

const csReadme = "# Generated SofaBuffers C# project\n\n" +
	"`@generated by sofabgen`. Encode/decode harness over `corelib-cs`.\n\n" +
	"```sh\nSOFAB_CS_CORELIB=/path/to/corelib-cs dotnet run -- encode <Message> < in.json\n```\n"

const csproj = `<!-- @generated by sofabgen -->
<Project Sdk="Microsoft.NET.Sdk">
  <PropertyGroup>
    <OutputType>Exe</OutputType>
    <TargetFramework>net9.0</TargetFramework>
    <Nullable>disable</Nullable>
    <ImplicitUsings>disable</ImplicitUsings>
    <InvariantGlobalization>true</InvariantGlobalization>
    <AssemblyName>harness</AssemblyName>
  </PropertyGroup>
  <ItemGroup>
    <ProjectReference Include="$(SOFAB_CS_CORELIB)/src/SofaBuffers/SofaBuffers.csproj" />
  </ItemGroup>
</Project>
`

func (g *gen) harness(s *ir.Schema) []byte {
	f := &cfile{}
	f.line("// Code generated by %s; DO NOT EDIT.", g.banner)
	f.line("using System;")
	f.line("using System.IO;")
	f.line("using System.Collections.Generic;")
	f.line("using System.Text.Json;")
	f.line("using System.Text.Json.Serialization;")
	f.line("using %s;", g.ns)
	f.blank()
	f.line("sealed class ByteArrayConverter : JsonConverter<byte[]> {")
	f.line("    public override byte[] Read(ref Utf8JsonReader r, Type t, JsonSerializerOptions o) {")
	f.line("        var list = new List<byte>();")
	f.line("        if (r.TokenType != JsonTokenType.StartArray) return Array.Empty<byte>();")
	f.line("        while (r.Read() && r.TokenType != JsonTokenType.EndArray) list.Add(r.GetByte());")
	f.line("        return list.ToArray();")
	f.line("    }")
	f.line("    public override void Write(Utf8JsonWriter w, byte[] v, JsonSerializerOptions o) {")
	f.line("        w.WriteStartArray(); foreach (var b in v) w.WriteNumberValue(b); w.WriteEndArray();")
	f.line("    }")
	f.line("}")
	f.blank()
	f.line("static class Program {")
	f.line("    static readonly JsonSerializerOptions Opts = new() { IncludeFields = true, Converters = { new ByteArrayConverter() } };")
	f.line("    static int Main(string[] args) {")
	f.line("        if (args.Length < 1) { Console.Error.WriteLine(\"usage: harness <encode|decode> [Message]\"); return 2; }")
	f.line("        string mode = args[0];")
	f.line("        string name = args.Length > 1 ? args[1] : %q;", defaultMessage(s))
	f.line("        using var ms = new MemoryStream();")
	f.line("        using (var stdin = Console.OpenStandardInput()) stdin.CopyTo(ms);")
	f.line("        var input = ms.ToArray();")
	f.line("        var stdout = Console.OpenStandardOutput();")
	f.line("        switch (name) {")
	for _, m := range s.Messages {
		mt := exported(m.Name)
		f.line("        case %q: {", m.Name)
		f.line("            if (mode == \"encode\") {")
		f.line("                var obj = JsonSerializer.Deserialize<%s>(input, Opts);", mt)
		f.line("                var bytes = obj.Encode(); stdout.Write(bytes, 0, bytes.Length);")
		f.line("            } else if (mode == \"decode\") {")
		f.line("                var obj = %s.Decode(input);", mt)
		f.line("                var json = JsonSerializer.SerializeToUtf8Bytes(obj, Opts);")
		f.line("                stdout.Write(json, 0, json.Length); stdout.WriteByte((byte)'\\n');")
		f.line("            } else { Console.Error.WriteLine(\"unknown mode\"); return 2; }")
		f.line("            break;")
		f.line("        }")
	}
	f.line("        default: Console.Error.WriteLine(\"unknown message\"); return 2;")
	f.line("        }")
	f.line("        return 0;")
	f.line("    }")
	f.line("}")
	return f.bytes()
}

func defaultMessage(s *ir.Schema) string {
	if len(s.Messages) > 0 {
		return s.Messages[0].Name
	}
	return ""
}

var _ = ir.KindU8
